import{_ as a,o as e,c as r,ag as l}from"./chunks/framework.DXGyWiRo.js";const b=JSON.parse('{"title":"杰克·伯恩（Jack Byrne）","description":"","frontmatter":{},"headers":[],"relativePath":"04_people/杰克·伯恩.md","filePath":"04_people/杰克·伯恩.md"}'),d={name:"04_people/杰克·伯恩.md"};function o(i,t,h,n,s,u){return e(),r("div",null,[...t[0]||(t[0]=[l('<h1 id="杰克·伯恩-jack-byrne" tabindex="-1">杰克·伯恩（Jack Byrne） <a class="header-anchor" href="#杰克·伯恩-jack-byrne" aria-label="Permalink to &quot;杰克·伯恩（Jack Byrne）&quot;">​</a></h1><h2 id="基本信息" tabindex="-1">基本信息 <a class="header-anchor" href="#基本信息" aria-label="Permalink to &quot;基本信息&quot;">​</a></h2><table tabindex="0"><thead><tr><th>属性</th><th>内容</th></tr></thead><tbody><tr><td>全名</td><td>John J. Byrne</td></tr><tr><td>出生</td><td>1930年代</td></tr><tr><td>职业</td><td>保险公司CEO</td></tr><tr><td>主要成就</td><td>拯救GEICO、Fireman&#39;s Fund</td></tr></tbody></table><h2 id="职业生涯" tabindex="-1">职业生涯 <a class="header-anchor" href="#职业生涯" aria-label="Permalink to &quot;职业生涯&quot;">​</a></h2><h3 id="geico扭转-1976-1985" tabindex="-1">GEICO扭转（1976-1985） <a class="header-anchor" href="#geico扭转-1976-1985" aria-label="Permalink to &quot;GEICO扭转（1976-1985）&quot;">​</a></h3><h4 id="背景" tabindex="-1">背景 <a class="header-anchor" href="#背景" aria-label="Permalink to &quot;背景&quot;">​</a></h4><ul><li><strong>1976年</strong>：GEICO因激进扩张和定价失误濒临破产</li><li>股价从高点暴跌至约2美元</li><li>公司面临破产清算风险</li></ul><h4 id="扭转行动" tabindex="-1">扭转行动 <a class="header-anchor" href="#扭转行动" aria-label="Permalink to &quot;扭转行动&quot;">​</a></h4><ol><li><strong>重建承保纪律</strong>：削减不盈利业务</li><li><strong>提价</strong>：修正定价不足问题</li><li><strong>注资</strong>：吸引新资本（包括伯克希尔）</li><li><strong>裁员</strong>：削减冗余成本</li></ol><h4 id="成果" tabindex="-1">成果 <a class="header-anchor" href="#成果" aria-label="Permalink to &quot;成果&quot;">​</a></h4><ul><li>公司从破产边缘恢复</li><li>1976-1985年保费增长稳健</li><li>综合成本率降至96左右</li><li>巴菲特大幅加仓，成为主要股东</li></ul><h3 id="fireman-s-fund-1985年后" tabindex="-1">Fireman&#39;s Fund（1985年后） <a class="header-anchor" href="#fireman-s-fund-1985年后" aria-label="Permalink to &quot;Fireman&#39;s Fund（1985年后）&quot;">​</a></h3><ul><li>1985年离开GEICO</li><li>任Fireman&#39;s Fund董事长兼CEO</li><li>巴菲特通过&quot;份额参与合同&quot;投资7%份额</li></ul><h2 id="管理风格" tabindex="-1">管理风格 <a class="header-anchor" href="#管理风格" aria-label="Permalink to &quot;管理风格&quot;">​</a></h2><h3 id="核心特点" tabindex="-1">核心特点 <a class="header-anchor" href="#核心特点" aria-label="Permalink to &quot;核心特点&quot;">​</a></h3><ol><li><strong>危机管理专家</strong>：擅长扭转困境企业</li><li><strong>承保纪律严格</strong>：不惜削减业务保持盈利</li><li><strong>培养接班人</strong>：离开GEICO时已培养好团队</li></ol><h3 id="巴菲特评价" tabindex="-1">巴菲特评价 <a class="header-anchor" href="#巴菲特评价" aria-label="Permalink to &quot;巴菲特评价&quot;">​</a></h3><blockquote><p>&quot;杰克·伯恩是真正非凡的管理天才。他在1976年拯救了GEICO，培养好了接班人，让我们感到非常幸运能与他合作。&quot; —— 1985年股东信</p></blockquote><blockquote><p>&quot;杰克在运营能力和资本配置能力上都非常出色，他通过回购股票大幅提升了GEICO股东权益。&quot; —— 1981年股东信</p></blockquote><h2 id="与伯克希尔关系" tabindex="-1">与伯克希尔关系 <a class="header-anchor" href="#与伯克希尔关系" aria-label="Permalink to &quot;与伯克希尔关系&quot;">​</a></h2><table tabindex="0"><thead><tr><th>事件</th><th>年份</th><th>内容</th></tr></thead><tbody><tr><td>GEICO扭转</td><td>1976</td><td>巴菲特投资，杰克任CEO</td></tr><tr><td>进入董事会</td><td>1976</td><td>巴菲特加入GEICO董事会</td></tr><tr><td>GEICO成功</td><td>1980-1985</td><td>公司恢复健康增长</td></tr><tr><td>Fireman&#39;s Fund</td><td>1985</td><td>巴菲特投资份额参与</td></tr></tbody></table><h2 id="接班人培养" tabindex="-1">接班人培养 <a class="header-anchor" href="#接班人培养" aria-label="Permalink to &quot;接班人培养&quot;">​</a></h2><table tabindex="0"><thead><tr><th>接班人</th><th>职位</th><th>成就</th></tr></thead><tbody><tr><td>Bill Snyder</td><td>董事长</td><td>继续压低成本</td></tr><tr><td>Lou Simpson</td><td>投资副总裁</td><td>管理投资组合</td></tr></tbody></table><h2 id="在股东信中的年份" tabindex="-1">在股东信中的年份 <a class="header-anchor" href="#在股东信中的年份" aria-label="Permalink to &quot;在股东信中的年份&quot;">​</a></h2><p>1976, 1977, 1978, 1979, 1980, 1981, 1982, 1983, 1984, 1985</p><h2 id="相关链接" tabindex="-1">相关链接 <a class="header-anchor" href="#相关链接" aria-label="Permalink to &quot;相关链接&quot;">​</a></h2><ul><li><a href="./../03_公司库/GEICO.html">GEICO</a> - 扭转的公司</li><li><a href="./菲尔·利切.html">菲尔·利切</a> - 同为保险管理明星</li><li><a href="./卢·辛普森.html">卢·辛普森</a> - GEICO投资经理</li></ul><hr><p><em>最后更新：2026-04-09</em></p>',29)])])}const q=a(d,[["render",o]]);export{b as __pageData,q as default};
